import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = new Array(n).fill(0).map(() => []);
    for (const [u, v, start, end] of edges) {
        adj[u].push([v, start, end]);
    }

    // Dijkstra's setup: priority queue sorted by time
    const pq = new MinPriorityQueue({ priority: (node) => node.time });
    pq.enqueue({ node: 0, time: 0 });

    const visited = new Array(n).fill(Infinity);
    visited[0] = 0;

    while (!pq.isEmpty()) {
        const { node, time } = pq.dequeue().element;
        if (node === n - 1) {
            return time;
        }
        if (time > visited[node]) {
            continue;
        }

        // Option 1: Stay at current node (time + 1)
        if (time + 1 < visited[node]) {
            visited[node] = time + 1;
            pq.enqueue({ node, time: time + 1 });
        }

        // Option 2: Try all outgoing edges
        for (const [v, start, end] of adj[node]) {
            if (time > end) {
                continue; // Edge is no longer available
            }
            const arrivalTime = Math.max(time, start) + 1;
            if (arrivalTime < visited[v]) {
                visited[v] = arrivalTime;
                pq.enqueue({ node: v, time: arrivalTime });
            }
        }
    }

    return -1;
}

